																			fp timeinst,
																			fp* initvalu,
																			fp* finavalu,
																			fp* parameter,

																			fp* error,
																			fp* initvalu_temp,
																			fp* finavalu_temp,
																			fp* com) {





	const fp c_1_11 = 41.0 / 840.0;
	const fp c6 = 34.0 / 105.0;
	const fp c_7_8= 9.0 / 35.0;
	const fp c_9_10 = 9.0 / 280.0;

	const fp a2 = 2.0 / 27.0;
	const fp a3 = 1.0 / 9.0;
	const fp a4 = 1.0 / 6.0;
	const fp a5 = 5.0 / 12.0;
	const fp a6 = 1.0 / 2.0;
	const fp a7 = 5.0 / 6.0;
	const fp a8 = 1.0 / 6.0;
